89	uint16_t get_canonical_mask(uint16_t mask_val) { 
90	    int current_L_for_canon = N_ACTUAL * (N_ACTUAL - 1) / 2;
91	    if (current_L_for_canon == 0) return 0; 
92	
93	    mask_to_adj_matrix_small_N(mask_val, N_ACTUAL, CANON_TMP_ADJ);
94	    
95	    std::iota(CANON_P_PERM.begin(), CANON_P_PERM.end(), 0); 
96	    uint16_t min_mask_representation = adj_matrix_to_mask_small_N(N_ACTUAL, CANON_TMP_ADJ, CANON_P_PERM);
97	
98	    while (std::next_permutation(CANON_P_PERM.begin(), CANON_P_PERM.end())) {
99	        uint16_t current_perm_mask = adj_matrix_to_mask_small_N(N_ACTUAL, CANON_TMP_ADJ, CANON_P_PERM);
100	        min_mask_representation = std::min(min_mask_representation, current_perm_mask);
101	    }
102	    return min_mask_representation;
103	}
