    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // Choose N: need at least M distinct graphs (s=0..M-1 gives M distinct)
    // Larger N gives more noise robustness but 1/N penalty in score
    // Heuristic: add some extra vertices for noise averaging
    int N;
    if (eps < 0.001) {
        N = std::max(4, M);
    } else {
        N = std::max(4, (int)std::ceil(M * (1.0 + 1.5 * eps)));
    }
    N = std::min(100, N);

    // Ensure we have at least M distinct s values in [0, N-1]
    if (N < M) N = M;
    N = std::min(100, std::max(4, N));

    int L = N * (N - 1) / 2;
    std::cout << N << "\n";

    // Construct M graphs using "k special vertices" approach
    // Graph with s special vertices: first s vertices connected to all others
    // Degree sequence: s vertices with degree N-1, N-s vertices with degree s
    // Evenly space s values from 0 to N-1
    std::vector<int> S(M); // number of special vertices for each graph
    if (M == 1) {
        S[0] = 0;
    } else {
        for (int k = 0; k < M; k++) {
            S[k] = (int)std::round((double)k * (N - 1) / (M - 1));
        }
        // Ensure all distinct
        for (int k = 1; k < M; k++) {
            if (S[k] <= S[k-1]) S[k] = S[k-1] + 1;
        }
        // Cap at N-1
        if (S[M-1] > N-1) {
            // Redistribute: use s = 0, 1, 2, ..., M-1 if M <= N
            for (int k = 0; k < M; k++) {
                S[k] = k;
            }
        }
    }

    // Output graphs
    for (int k = 0; k < M; k++) {
        int s = S[k];
        std::string g(L, '0');
        int idx = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                // Edge exists if i < s or j < s (at least one is special)
                if (i < s || j < s) {
                    g[idx] = '1';
                }
                idx++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Precompute: number of edges in each G_k
    // edges_in_G(s) = s*(2N - s - 1) / 2
    std::vector<int> edges_in_G(M);
    for (int k = 0; k < M; k++) {
        int s = S[k];
        edges_in_G[k] = s * (2 * N - s - 1) / 2;
    }

    // Process 100 queries
    // For each query H, we use the approximate GED decoder:
    // For graph G_k with s special vertices:
    //   - Assign top-s degree vertices of H as "special"
    //   - Hamming = edges_in_G(s) - total_edges_H + 2 * E_NN
    //   where E_NN = edges among the non-special (bottom N-s degree) vertices
    // Pick k with minimum Hamming

    // Store adjacency for H
    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

    for (int q = 0; q < 100; q++) {
        std::string h_str;
        std::cin >> h_str;

        // Build adjacency matrix and compute degrees
        std::vector<int> deg(N, 0);
        int total_edges = 0;
        int idx = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                bool has_edge = (h_str[idx] == '1');
                adj[i][j] = adj[j][i] = has_edge;
                if (has_edge) {
                    deg[i]++;
                    deg[j]++;
                    total_edges++;
                }
                idx++;
            }
        }

        // Sort vertices by degree (descending)
        std::vector<int> order(N);
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] > deg[b];
        });

        // Compute edges_below(s) for s = 0, 1, ..., N
        // edges_below(s) = edges among vertices order[s], order[s+1], ..., order[N-1]
        // Compute incrementally from s = N down to 0
        std::vector<int> edges_below(N + 1, 0);
        // edges_below[N] = 0
        // edges_below[s] = edges_below[s+1] + (edges from order[s] to order[s+1..N-1])
        for (int s = N - 1; s >= 0; s--) {
            int v = order[s];
            int count = 0;
            for (int t = s + 1; t < N; t++) {
                if (adj[v][order[t]]) count++;
            }
            edges_below[s] = edges_below[s + 1] + count;
        }

        // For each candidate G_k, compute Hamming distance
        int best_k = 0;
        int best_hamming = L + 1;

        for (int k = 0; k < M; k++) {
            int s = S[k];
            // Hamming = edges_in_G(s) - total_edges + 2 * edges_below(s)
            int hamming = edges_in_G[k] - total_edges + 2 * edges_below[s];
            if (hamming < best_hamming) {
                best_hamming = hamming;
                best_k = k;
            }
        }

        std::cout << best_k << "\n";
        std::cout.flush();
    }

    return 0;
}
