    // With s special vertices approach and degree-based decoding,
    // we need N >= M (so S values can be distinct: 0, 1, ..., M-1)
    // Larger N increases L = N(N-1)/2 which reduces noise impact but costs 1/N in score
    // The error probability depends on separation between adjacent graphs
    // For adjacent graphs (s vs s+1), the difference in edge count is (N-1) - s ~ N
    // Noise std ~ sqrt(L * eps * (1-eps))
    // We want separation >> noise, but also N small

    // For the special vertex approach, adjacent graphs differ by N-1-2s edges
    // (adding vertex s as special adds edges to all N-1-s non-special vertices,
    //  but removes 0 edges). Actually difference = N-1-s for going from s to s+1.
    // Minimum separation (at s=M-2 going to s=M-1) = N-M+1
    // Expected noise in Hamming = L*eps for added + (L-edges_in_G)*eps...
    // Actually expected Hamming under correct assignment ~ L*eps (each bit flips w.p. eps)
    // Std of Hamming ~ sqrt(L*eps*(1-eps))
    // We need separation N-M+1 >> sqrt(L*eps*(1-eps)) = sqrt(N(N-1)/2 * eps*(1-eps))

    // Set N = M + extra, try to balance
    int N;
    if (eps < 0.001) {
        // No noise: just use N = M, perfect decoding
        N = M;
    } else {
        // We want (N - M + 1)^2 >> N^2/2 * eps*(1-eps) * k^2 for some safety factor k
        // Solving: let d = N - M + 1. d^2 > k^2 * N^2/2 * eps*(1-eps)
        // d > k * N * sqrt(eps*(1-eps)/2)
        // N - M + 1 > k * N * sqrt(eps*(1-eps)/2)
        // N(1 - k*sqrt(eps*(1-eps)/2)) > M - 1
        // N > (M-1) / (1 - k*sqrt(eps*(1-eps)/2))
        double noise_factor = std::sqrt(eps * (1.0 - eps) / 2.0);
        double k = 3.0; // safety factor for ~3 sigma separation
        double denom = 1.0 - k * noise_factor;
        if (denom <= 0.1) {
            N = 100; // high noise, use max
        } else {
            N = (int)std::ceil((M - 1.0) / denom) + 1;
        }
    }
    N = std::min(100, std::max(M, std::max(4, N)));

