    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

    for (int q = 0; q < 100; q++) {
        std::string h_str;
        std::cin >> h_str;

        // Build adjacency and degrees
        std::vector<int> deg(N, 0);
        int total_edges = 0;
        int idx = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                bool has_edge = (h_str[idx] == '1');
                adj[i][j] = adj[j][i] = has_edge;
                if (has_edge) {
                    deg[i]++;
                    deg[j]++;
                    total_edges++;
                }
                idx++;
            }
        }

        // Sort vertices by degree descending
        std::vector<int> order(N);
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] > deg[b];
        });

        // Compute edges_below[s] = edges among order[s..N-1]
        std::vector<int> edges_below(N + 1, 0);
        for (int s = N - 1; s >= 0; s--) {
            int v = order[s];
            int count = 0;
            for (int t = s + 1; t < N; t++) {
                if (adj[v][order[t]]) count++;
            }
            edges_below[s] = edges_below[s + 1] + count;
        }

        // For each candidate, compute Hamming under degree-based assignment
        // Hamming(k) = edges_in_G[k] - total_edges + 2 * edges_below[S[k]]
        int best_k = 0;
        int best_hamming = L + 1;

        for (int k = 0; k < M; k++) {
            int s = S[k];
            int hamming = edges_in_G[k] - total_edges + 2 * edges_below[s];
            if (hamming < best_hamming) {
                best_hamming = hamming;
                best_k = k;
            }
        }

